+func preferDeviceSet(best, candidate map[string]Device) map[string]Device {
+	if len(candidate) == 0 {
+		return best
+	}
+	if len(candidate) > len(best) {
+		return cloneDeviceMap(candidate)
+	}
+	if len(candidate) == len(best) {
+		out := cloneDeviceMap(best)
+		for k, v := range candidate {
+			if _, ok := out[k]; !ok {
+				out[k] = v
+			}
+		}
+		return out
+	}
+	return best
+}
