+func toMember(groupCoordinatorUUID string, m zgsMember) (Member, bool) {
+	ip, err := hostToIP(m.Location)
+	if err != nil || ip == "" {
+		return Member{}, false
+	}
+	mem := Member{
+		Name:      m.ZoneName,
+		IP:        ip,
+		UUID:      m.UUID,
+		Location:  m.Location,
+		IsVisible: m.Invisible != "1",
+	}
+	if groupCoordinatorUUID != "" {
+		mem.IsCoordinator = mem.UUID == groupCoordinatorUUID
+	}
+	return mem, true
+}
